import React, { useEffect, useState } from "react";
import axios from "axios";

function App() {
  const [alerts, setAlerts] = useState([]);

  // SOS function
  const sendSOS = () => {
    navigator.geolocation.getCurrentPosition(async (pos) => {
      const latitude = pos.coords.latitude;
      const longitude = pos.coords.longitude;

      try {
        await axios.post("http://localhost:5000/alert", {
          latitude,
          longitude
        });

        alert("SOS Sent 🚨");
        fetchAlerts();
      } catch (err) {
        console.log(err);
      }
    });
  };

  // Fetch alerts
  const fetchAlerts = async () => {
    const res = await axios.get("http://localhost:5000/alerts");
    setAlerts(res.data);
  };

  useEffect(() => {
    fetchAlerts();
  }, []);

  return (
    <div style={{ textAlign: "center", padding: "20px" }}>
      <h1>Women Safety App 🚀</h1>

      <button
        onClick={sendSOS}
        style={{
          padding: "15px",
          fontSize: "18px",
          backgroundColor: "red",
          color: "white",
          border: "none",
          borderRadius: "10px"
        }}
      >
        🚨 SOS
      </button>

      <h2>Alert History</h2>

      {alerts.map((a, index) => (
        <div key={index} style={{ margin: "10px" }}>
          📍 {a.latitude}, {a.longitude}
        </div>
      ))}
    </div>
  );
}

export default App;
